-- Normalize province names to standard South African province names
UPDATE properties SET province = 'Western Cape' WHERE province ILIKE '%western cap%' AND province != 'Western Cape';
UPDATE properties SET province = 'Gauteng' WHERE province ILIKE '%gauteng%' AND province != 'Gauteng';
UPDATE properties SET province = 'KwaZulu-Natal' WHERE (province ILIKE '%kwazulu%' OR province ILIKE '%kzn%') AND province != 'KwaZulu-Natal';
UPDATE properties SET province = 'Eastern Cape' WHERE province ILIKE '%eastern cap%' AND province != 'Eastern Cape';
UPDATE properties SET province = 'Limpopo' WHERE province ILIKE '%limpopo%' AND province != 'Limpopo';
UPDATE properties SET province = 'Mpumalanga' WHERE province ILIKE '%mpumalanga%' AND province != 'Mpumalanga';
UPDATE properties SET province = 'North West' WHERE province ILIKE '%north west%' AND province != 'North West';
UPDATE properties SET province = 'Northern Cape' WHERE province ILIKE '%northern cap%' AND province != 'Northern Cape';
UPDATE properties SET province = 'Free State' WHERE province ILIKE '%free state%' AND province != 'Free State';
SELECT 'Normalization complete' AS result;

parameters.jsCode:
const urlDupes = $('Find URL Duplicates').all().length;
const nearDupes = $('Find Near-Duplicate Properties').all().length;
const qualityIssues = $('Find Data Quality Issues').all().map(i => i.json);
const removedDupes = $('Mark Duplicates as Removed').all().length;
const staledListings = $('Flag Stale Listings').all().length;

const issuesSummary = qualityIssues.map(i => `• ${i.issue_type}: ${i.count}`).join('\n');

const totalIssues = qualityIssues.reduce((s, i) => s + Number(i.count), 0);

return [{
  json: {
    report_date: new Date().toLocaleDateString('en-ZA'),
    url_duplicates_found: urlDupes,
    near_duplicates_found: nearDupes,
    duplicates_removed: removedDupes,
    stale_listings_flagged: staledListings,
    quality_issues: qualityIssues,
    total_quality_issues: totalIssues,
    issues_summary: issuesSummary
  }
}];

